def test_ideas_release_audit_maps_original_roadmap_items(
    runner: CliRunner,
) -> None:
    """Every docs/ideas.md roadmap item has package capability proof."""
    document = ideas_document_check()
    assert document["format"] == "appgen.ideas-document-check.v1"
    assert document["ok"] is True

    rows = ideas_requirement_rows()
    assert len(rows) == 64
    assert {row["section"] for row in rows} == {
        "ecosystem",
        "other_stuff",
        "big_things",
        "docker_deployment",
        "dbscript_ideas",
        "extended_bullets",
    }
    assert {"dbml_sql_ponyorm_generation", "existing_database_generation"} <= {
        row["id"] for row in rows
    }

    sections = ideas_section_summary(rows)
    assert all(section["ok"] for section in sections)

    audit = ideas_release_audit()
    assert audit["format"] == "appgen.ideas-release-audit.v1"
    assert audit["ok"] is True
    assert {
        "document_contract",
        "roadmap_item_coverage",
        "section_coverage",
        "generation_smoke",
    } == {gate["id"] for gate in audit["gates"]}
    palette_gate = next(gate for gate in audit["gates"] if gate["id"] == "palette_breadth")
    assert palette_gate["ok"] is True
    assert set(palette_gate["required_categories"]) <= set(palette_gate["passing_categories"])
    canvas_gate = next(gate for gate in audit["gates"] if gate["id"] == "canvas_contract")
    assert canvas_gate["ok"] is True
    assert canvas_gate["passing_columns"] == canvas_gate["required_columns"]
    assert set(canvas_gate["required_targets"]) <= set(canvas_gate["passing_targets"])
    assert audit["generation_smoke"]["ok"] is True
    smoke = ideas_generation_smoke_audit()
    assert smoke["format"] == "appgen.ideas-generation-smoke-audit.v1"
    assert smoke["ok"] is True
    assert {"jhipster/appgen_jhipster.py", "automation/appgen_node_red.py", "deploy/appgen_deploy.py"} <= set(
        smoke["required_artifacts"]
    )

    result = runner.invoke(__main__.main, ["--ideas-release-audit"])

    assert result.exit_code == 0
    cli_report = json.loads(result.output)
    assert cli_report["ok"] is True
    assert cli_report["decision"] == "approved"
    assert cli_report["gates"][1]["total"] == 64


