def test_package_visual_modeling_audit_covers_visual_schema_generation(
    runner: CliRunner,
) -> None:
    """The package proves visual models can regenerate schema/code plans."""
    model = visual_schema()
    assert model["format"] == "appgen.package-visual-schema.v1"
    assert {"Author", "Book"} == {table["name"] for table in model["tables"]}
    assert model["relations"][0]["target_table"] == "Author"

    graph = visual_graph()
    assert graph["format"] == "appgen.package-visual-graph.v1"
    assert graph["ok"] is True
    assert any(edge["type"] == "relationship" for edge in graph["edges"])

    erd = package_erd_mermaid()
    assert erd.startswith("erDiagram\n")
    assert "Author ||--o{ Book" in erd

    exports = visual_model_exports()
    assert exports["format"] == "appgen.package-visual-model-exports.v1"
    assert "Table Book" in exports["dbml"]
    assert "CREATE TABLE Book" in exports["sql"]
    assert "class Book(db.Entity)" in exports["ponyorm"]

    table = visual_table_proposal("Publisher")
    field = visual_field_proposal("Book", "subtitle")
    relation = visual_relationship_proposal("Book", "publisher_id", "Publisher")
    assert table["kind"] == "add_table"
    assert field["dsl"] == "  subtitle: string"
    assert relation["dsl"] == "  publisher_id: int -> Publisher.id [many-to-one]"

    migration = visual_migration_preview(relation)
    assert migration["format"] == "appgen.package-visual-migration-preview.v1"
    assert migration["requires_review"] is True
    assert migration["operations"][0]["op"] == "add_column"

    generation = code_generation_plan(relation)
    assert generation["format"] == "appgen.package-visual-code-generation-plan.v1"
    assert "app/models.py" in generation["artifacts"]
    assert "migration_preview" in generation["checks"]

    audit = visual_modeling_release_audit()
    assert audit["format"] == "appgen.package-visual-modeling-release-audit.v1"
    assert audit["ok"] is True
    assert {
        "visual_graph",
        "erd_export",
        "schema_exports",
        "proposal_breadth",
        "migration_preview",
        "code_generation_plan",
        "artifact_contract",
        "generation_smoke",
    } == {gate["id"] for gate in audit["gates"]}
    assert audit["generation_smoke"]["ok"] is True

    smoke = visual_modeling_generation_smoke_audit()
    assert smoke["format"] == "appgen.visual-modeling-generation-smoke-audit.v1"
    assert smoke["ok"] is True
    assert {
        "app/designer.py",
        "app/templates/appgen_designer.html",
        "app/appgen.json",
    } <= set(smoke["required_artifacts"])
    assert "app/designer.py" in set(smoke["compiled_artifacts"])

    missing = visual_modeling_release_audit(existing_paths={"app/designer.py"})
    assert missing["ok"] is False
    assert any(gate["id"] == "artifact_contract" for gate in missing["blocking_gaps"])

    result = runner.invoke(__main__.main, ["--visual-modeling-release-audit"])
    assert result.exit_code == 0
    report = json.loads(result.output)
    assert report["ok"] is True
    assert report["graph"]["ok"] is True


def test_package_security_audit_covers_auth_identity_and_compliance(
    runner: CliRunner,
) -> None:
    """The package proves RBAC, SSO, tenant/RLS, session, and compliance guards."""
    policies = package_role_policy_catalog()
    assert any(
        policy["role"] == "Analyst"
        and policy["resource"] == "Project"
        and "update" in policy["actions"]
        for policy in policies
    )

    principal = package_normalize_principal(
        {"sub": "u1", "roles": ["Analyst"], "tenant_id": "42", "provider": "oidc"}
    )
    assert principal["roles"] == ("Analyst",)
    allow = package_authorize(principal, "Project", "update")
    deny = package_authorize(principal, "Project", "delete")
    assert allow["allowed"] is True
    assert deny["allowed"] is False
    assert package_authorization_audit_event(deny)["event"] == "security.authorization.denied"

    env = {
        "OIDC_ISSUER": "https://idp.example.test",
        "OIDC_CLIENT_ID": "client",
        "OIDC_CLIENT_SECRET": "env-secret",
        "SAML_METADATA_URL": "https://idp.example.test/metadata",
        "SAML_ENTITY_ID": "appgen",
        "LDAP_URL": "ldaps://directory.example.test",
        "LDAP_BIND_DN": "cn=appgen",
        "LDAP_BIND_PASSWORD": "env-secret",
        "AD_DOMAIN": "example.test",
        "AD_CLIENT_ID": "client",
        "AD_CLIENT_SECRET": "env-secret",
        "COGNITO_DOMAIN": "auth.example.test",
        "COGNITO_CLIENT_ID": "client",
        "COGNITO_CLIENT_SECRET": "env-secret",
    }
    providers = sso_provider_catalog(env)
    assert {item["provider"] for item in providers} == {
        "oidc",
        "saml",
        "ldap",
        "active_directory",
        "cognito",
    }
    assert all(item["configured"] for item in providers)
    assert all(item["secret_policy"] == "env-only" for item in providers)
    assert all(item["configured"] is False for item in sso_provider_catalog({}))

    rls = tenant_rls_contract()
    assert rls["format"] == "appgen.package-tenant-rls-contract.v1"
    assert rls["target"] == {"table": "Project", "field": "org_id"}
    assert "CREATE POLICY" in rls["postgres_policy_sql"]

    session = session_hardening_policy()
    assert session["idle_timeout_seconds"] == 1800
    assert session["auto_logout"] is True
    assert session["headers"]["X-Frame-Options"] == "DENY"

    compliance = package_compliance_contract()
    assert compliance["format"] == "appgen.package-compliance-contract.v1"
    assert {"GDPR", "HIPAA-ready"} <= set(compliance["regulatory_profiles"])

    assert package_secret_exposure_scan({"SECRET_KEY": "managed-secret"})["ok"] is True
    assert package_secret_exposure_scan({"SECRET_KEY": "change-me"})["ok"] is False

    audit = security_release_audit()
    assert audit["format"] == "appgen.package-security-release-audit.v1"
    assert audit["ok"] is True
    assert {
        "rbac_authorization",
        "authorization_audit",
        "sso_provider_coverage",
        "sso_missing_secret_guard",
        "tenant_rls",
        "session_hardening",
        "compliance_privacy",
        "secret_exposure_scan",
        "artifact_contract",
        "generation_smoke",
    } == {gate["id"] for gate in audit["gates"]}
    assert audit["generation_smoke"]["ok"] is True

    smoke = security_generation_smoke_audit()
    assert smoke["format"] == "appgen.security-generation-smoke-audit.v1"
    assert smoke["ok"] is True
    assert {
        "app/security.py",
        "app/runtime_security.py",
        "app/identity.py",
        "app/tenancy.py",
        "app/rls.py",
        "app/compliance.py",
    } <= set(smoke["required_artifacts"])
    assert {
        "app/security.py",
        "app/runtime_security.py",
        "app/identity.py",
        "app/tenancy.py",
        "app/rls.py",
        "app/compliance.py",
    } <= set(smoke["compiled_artifacts"])

    missing = security_release_audit(existing_paths={"app/security.py"})
    assert missing["ok"] is False
    assert any(gate["id"] == "artifact_contract" for gate in missing["blocking_gaps"])

    result = runner.invoke(__main__.main, ["--security-release-audit"])
    assert result.exit_code == 0
    report = json.loads(result.output)
    assert report["ok"] is True
    assert report["decisions"]["deny"]["allowed"] is False


